#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new;

# Allowlist of valid redirect destinations
my %ALLOWED_ROUTES = (
    'dashboard'  => '/app/dashboard',
    'profile'    => '/app/profile',
    'settings'   => '/app/settings',
    'home'       => '/index.html',
    'admin'      => '/admin/panel',
    'reports'    => '/app/reports',
);

# Default redirect if none specified or invalid
my $DEFAULT_REDIRECT = '/app/dashboard';

# Get the 'next' parameter from query string
my $next_param = $cgi->param('next') || '';

# Sanitize input - remove any whitespace
$next_param =~ s/^\s+|\s+$//g;

my $redirect_url;

# Check if the parameter matches a route identifier
if ($next_param && exists $ALLOWED_ROUTES{$next_param}) {
    $redirect_url = $ALLOWED_ROUTES{$next_param};
} 
# Alternative: Check if it's a relative path in the allowlist
elsif ($next_param && grep { $_ eq $next_param } values %ALLOWED_ROUTES) {
    $redirect_url = $next_param;
}
# Default fallback
else {
    $redirect_url = $DEFAULT_REDIRECT;
}

# Ensure the redirect URL is relative (additional safety check)
if ($redirect_url =~ m{^https?://}i || $redirect_url =~ m{^//}) {
    $redirect_url = $DEFAULT_REDIRECT;
}

# Send redirect header
print $cgi->header(
    -type     => 'text/html',
    -status   => '302 Found',
    -location => $redirect_url
);

exit;